INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1', '디지털채널본부', '은행의 모든 비대면(Untact) 고객 접점을 총괄하는 컨트롤 타워입니다. 모바일 뱅킹, 인터넷 뱅킹 앱의 기획, 개발, 운영, 마케팅, 그리고 사용자 경험(UX/UI) 혁신까지 디지털 채널에서 일어나는 모든 활동을 책임집니다. 고객이 지점을 방문하지 않고도 모든 금융 서비스를 원활하게 이용할 수 있도록 만드는 것이 본부의 핵심 목표입니다.', ARRAY['디지털', '모바일', '인터넷뱅킹', '비대면', '온라인', '채널', '디지털전략', '채널통합', '전사정책'], '앱의 전반적인 사용성, 디자인, 기능 배치, 알림 서비스 등 특정 금융 상품(예: 대출, 외환)이 아닌, 디지털 채널 자체의 경험과 관련된 모든 리뷰를 포괄적으로 다룹니다. 채널 간 연동 문제, 전사 디지털 정책 관련 이슈도 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1', '모바일뱅킹부', '스마트폰과 태블릿에서 사용하는 모바일 뱅킹 앱의 모든 기능과 서비스를 기획하고 운영하는 조직입니다. 모바일 앱의 전체적인 서비스 방향성, 사용자 정책, 마케팅 전략을 수립하며, 앱스토어 관리와 앱 버전 업데이트 정책도 담당합니다. MAU(월간 활성 사용자), 거래량 등 모바일 채널의 핵심 성과지표에 대한 책임을 집니다.', ARRAY['모바일', '앱', '스마트폰', '모바일뱅킹', '앱스토어', '모바일정책', 'MAU', '앱업데이트'], '모바일 앱 전반의 성능, 정책, 사용자 경험 관련 이슈. 특정 기능에 국한되지 않은 앱 전체의 문제들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-2', '인터넷뱅킹부', '웹 브라우저 기반 인터넷뱅킹 서비스를 전담하여 기획, 개발, 운영합니다. PC와 모바일 웹에서의 금융 서비스 제공, 웹 보안 정책 수립, 브라우저 호환성 관리 등을 담당하며, 인터넷뱅킹 채널의 안정성과 편의성을 책임집니다.', ARRAY['인터넷뱅킹', '웹', 'PC뱅킹', '브라우저', '웹보안', '호환성'], '인터넷뱅킹 웹사이트 전반의 접속, 성능, 보안, 호환성 관련 이슈. 웹 채널 특유의 문제들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3', 'UX/UI혁신부', '디지털 채널의 사용자 경험과 화면 인터페이스 개선을 총괄하여 고객 만족도와 사용성을 향상시킵니다. 전반적인 UX/UI 정책과 디자인 가이드라인 수립, 사용자 행동 분석, 접근성 개선, 디자인 시스템 구축 등을 담당합니다.', ARRAY['UX', 'UI', '사용자경험', '인터페이스', '디자인', '사용성', '접근성', '디자인시스템'], '화면 디자인, 메뉴 구조, 사용 편의성, 접근성, 시각적 요소 등 사용자 경험 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-1', '계좌조회서비스팀', '모바일 앱에서 고객이 가장 많이 사용하는 기본 기능인 계좌 관련 조회 서비스를 전담하는 조직입니다. 잔액 조회, 거래내역 확인, 입출금 현황 등 계좌 정보를 고객에게 정확하고 신속하게 제공하는 것이 핵심 업무입니다. 백엔드 계정계 시스템과 모바일 앱 간의 데이터 연동 아키텍처를 설계하고, 조회 성능 최적화와 데이터 정합성 관리를 책임집니다.', ARRAY['계좌조회', '잔액', '거래내역', '계좌정보', '조회서비스', '데이터연동', '계정계연동'], '계좌조회 서비스 전반의 기획, 정책, 성능 관련 이슈. 특정 기술적 오류가 아닌 조회 서비스 자체의 개선사항들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-2', '자동이체지원파트', '모바일 앱의 자동이체 서비스를 전담하여 고객의 반복적인 금융 거래를 자동화합니다. 자동이체 정책 수립, 서비스 기획, 등록/변경/해지 프로세스 관리, 자동이체 실행 모니터링 등 자동이체와 관련된 모든 업무를 통합 관리합니다.', ARRAY['자동이체', '정기이체', '자동납부', '이체정책', '반복거래'], '자동이체 서비스 전반의 정책, 프로세스, 사용 편의성 관련 이슈. 등록/해지 절차의 복잡성, 정책 관련 문의 등을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-3', '푸시알림관리팀', '모바일 앱의 푸시 알림 시스템 전반을 관리하여 고객에게 적시에 필요한 정보를 전달합니다. 알림 정책 수립, 발송 전략 기획, 개인화 알림 서비스, 알림 성과 분석 등을 담당하며, 고객의 금융 활동을 효과적으로 지원하는 커뮤니케이션 채널을 운영합니다.', ARRAY['푸시알림', '알림', '메시지', 'notification', '알림정책', '개인화알림'], '푸시 알림 서비스 전반의 정책, 전략, 개인화 설정 관련 이슈. 알림 종류나 발송 정책에 대한 문의 등을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-2-1', '이체서비스개발팀', '인터넷뱅킹의 이체 관련 신규 기능 개발과 기존 기능 개선을 담당합니다. 이체 서비스의 신기능 기획, 사용자 요구사항 분석, 개발 로드맵 수립, 기능 개선 등을 통해 인터넷뱅킹 이체 서비스의 경쟁력을 높입니다.', ARRAY['이체개발', '신규이체기능', '이체기능개선', '기능기획', '개발로드맵'], '새로운 이체 기능 요청, 기존 기능 개선 제안, 이체 서비스 기획 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-2-2', '이체서비스운영팀', '인터넷뱅킹의 기존 이체 서비스 안정 운영과 품질 관리를 담당합니다. 이체 서비스 운영 정책 수립, 성능 모니터링, 서비스 품질 관리, 운영 이슈 대응 등을 통해 고객이 안전하고 신뢰할 수 있는 이체 서비스를 이용할 수 있도록 합니다.', ARRAY['이체운영', '이체서비스안정성', '운영정책', '품질관리', '성능모니터링'], '이체 서비스의 안정성, 운영 정책, 전반적인 서비스 품질 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-1', '모바일UX설계팀', '모바일 앱의 사용자 경험 설계를 전담하여 직관적이고 편리한 앱 환경을 만듭니다. 사용자 여정 분석, 정보 구조 설계, 인터랙션 디자인, 사용성 테스트 등을 통해 모바일 환경에 최적화된 UX를 제공합니다.', ARRAY['모바일UX', '앱설계', '사용자경험', '사용자여정', '인터랙션디자인', '사용성테스트'], '모바일 앱의 전반적인 사용자 경험, 앱 구조, 사용 흐름 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-2', '접근성개선파트', '디지털 서비스의 접근성 개선 업무를 전담하여 모든 고객이 차별 없이 금융 서비스를 이용할 수 있도록 합니다. 웹 접근성 가이드라인 준수, 장애인 지원 기능 개발, 고령자 친화적 인터페이스 구축 등을 통해 포용적인 디지털 금융 환경을 조성합니다.', ARRAY['접근성', '장애인지원', '유니버설디자인', '웹접근성', '고령자친화', '포용적디자인'], '접근성 관련 정책, 장애인 지원 기능, 고령자 사용 편의성 등 접근성 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-3', '화면QA셀', '디지털 채널의 화면 품질 검증을 전담하여 오류 없는 사용자 인터페이스를 보장합니다. 화면 기능 테스트, UI 품질 검증, 다양한 디바이스 호환성 테스트 등을 통해 고품질의 디지털 서비스를 제공합니다.', ARRAY['화면QA', '화면품질', 'UI테스트', '품질검증', '호환성테스트'], '화면 품질, UI 버그, 테스트 관련 전반적인 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-1-1', '잔액처리파트', '계좌 잔액 조회와 관련된 모든 데이터 처리를 담당하여 정확한 잔액 정보를 제공합니다. 잔액 처리 로직 설계, 시스템 간 연동 관리, 잔액 데이터 검증 등을 통해 고객이 신뢰할 수 있는 잔액 정보를 실시간으로 확인할 수 있도록 합니다.', ARRAY['잔액처리', '잔액조회', '잔액불일치', '잔액로직', '데이터검증'], '잔액 처리 로직, 연동 시스템, 데이터 검증 등 잔액 처리 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-1-2', '거래내역파트', '거래내역 조회와 관련된 모든 데이터 처리를 담당하여 완전하고 정확한 거래 이력을 제공합니다. 거래내역 처리 로직 설계, 데이터 수집 및 정제, 내역 표시 최적화 등을 통해 고객이 자신의 금융 활동을 명확하게 파악할 수 있도록 합니다.', ARRAY['거래내역', '거래이력', '내역조회', '거래내역누락', '내역처리로직'], '거래내역 처리 로직, 데이터 수집, 내역 표시 방식 등 거래내역 처리 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-2-1', '등록관리셀', '자동이체 서비스의 등록, 변경, 해지 업무를 전문적으로 관리합니다. 고객이 자동이체를 신규 등록할 때부터 해지할 때까지의 모든 라이프사이클을 담당하며, 등록 데이터의 정합성 검증, 등록 오류 처리, 등록 현황 모니터링 등 자동이체 등록 관리의 모든 세부 업무를 전담합니다.', ARRAY['등록관리', '신규등록', '변경처리', '해지처리', '등록오류', '데이터검증', '등록현황', '라이프사이클관리'], '자동이체 등록/변경/해지 과정에서 발생하는 구체적인 기술적 오류, 등록 실패 사례, 데이터 불일치 문제, 등록 절차상의 세부적인 불편사항 등 등록 프로세스의 실행 단계에서 나타나는 이슈를 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
