VALUES ('1-2-2-1', '예약이체파트', '예약이체 서비스를 전담하여 고객이 미래의 특정 시점에 자동으로 이체를 실행할 수 있도록 합니다. 예약이체 스케줄링 시스템 구축, 실행 모니터링, 예약 관리 기능 개발 등을 담당합니다.', ARRAY['예약이체', '이체예약', '예약이체미실행', '스케줄링', '예약관리'], '예약이체 기능, 스케줄링 시스템, 예약 관리 등 예약이체 서비스 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-1-1', '메뉴구조파트', '모바일 앱의 메뉴 구조와 정보 설계를 담당하여 직관적인 앱 네비게이션을 제공합니다. 정보 아키텍처 설계, 메뉴 분류 체계 구축, 사용자 동선 최적화 등을 통해 고객이 원하는 기능을 쉽고 빠르게 찾을 수 있도록 합니다.', ARRAY['메뉴구조', '메뉴위치', '네비게이션', '메뉴불편', '정보아키텍처'], '메뉴 구조, 정보 분류, 네비게이션 설계 등 앱 구조 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-2-1', '시각가독성셀', '글꼴, 색상, 대비 등 시각적 가독성을 전문적으로 개선하는 최말단 접근성 조직입니다. 텍스트 가독성 테스트, 색상 대비 최적화, 폰트 크기 조정, 시각적 계층 구조 개선 등을 통해 모든 고객이 화면 내용을 명확하게 인식할 수 있도록 합니다.', ARRAY['시각가독성', '글씨크기', '색상대비', '가독성', '폰트최적화'], '글씨가 너무 작음, 색상 대비 부족, 텍스트가 잘 안 보임 등 시각적 가독성 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-2-2', '장애인지원셀', '시각, 청각, 지체 장애인을 위한 접근성 기능을 전문적으로 개발하고 지원하는 최말단 접근성 조직입니다. 스크린 리더 호환성 개선, 음성 안내 기능 구축, 대체 텍스트 제공, 키보드 네비게이션 지원 등을 통해 장애인도 동등하게 금융 서비스를 이용할 수 있도록 합니다.', ARRAY['장애인지원', '접근성', '음성안내', '화면읽기', '스크린리더', '키보드네비게이션'], '스크린 리더 인식 불가, 음성 안내 부족, 키보드로 조작 불가 등 장애인 접근성 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-3-1', '입력오류분석셀', '화면 내 버튼, 입력 필드 등의 오작동을 전문적으로 분석하고 수정하는 최말단 QA 조직입니다. 터치/클릭 이벤트 오류 진단, 입력값 처리 로직 검증, 폼 유효성 검사 오류 수정 등을 통해 고객이 화면에서 모든 입력과 조작을 정상적으로 수행할 수 있도록 보장합니다.', ARRAY['입력오류', '버튼오류', '입력필드오류', '화면오작동', '터치이벤트오류'], '버튼이 안 눌림, 입력값이 저장 안됨, 폼 제출 오류 등 화면 조작 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-1-1-1', '실시간잔액관리셀', '계좌 잔액이 고객에게 실시간으로 정확하게 표시되도록 하는 기술적 처리를 전문적으로 담당하는 최말단 실무 조직입니다. 입출금 거래 발생 시 잔액 업데이트 로직, 다중 채널(모바일앱, 인터넷뱅킹, ATM) 간 잔액 동기화, 시스템 간 데이터 정합성 검증을 실시간으로 처리합니다. 특히 대용량 거래가 몰리는 시간대의 성능 최적화와 장애 발생 시 긴급 복구 작업을 직접 수행합니다.', ARRAY['실시간잔액', '잔액동기화', '잔액불일치', '잔액지연', '잔액업데이트', '데이터정합성'], '잔액 반영 지연, 시스템 간 잔액 불일치, 음수 잔액 표시 등 잔액 관련 기술적 오류를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-1-2-1', '내역동기화셀', '거래내역의 시스템 간 동기화와 데이터 일관성을 전문적으로 관리하는 최말단 기술 조직입니다. 거래 발생 시 각종 시스템 간 내역 전파, 누락된 거래내역 복구, 데이터 불일치 해결 등을 실시간으로 처리하여 고객이 완전한 거래 이력을 확인할 수 있도록 합니다.', ARRAY['내역동기화', '거래내역누락', '내역지연', '데이터일관성', '시스템간동기화'], '거래내역 누락, 지연 반영, 시스템 간 데이터 불일치 등 거래내역 동기화 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-1-3-1-1', '누락알림셀', '푸시 알림 누락 사례를 전문적으로 분석하고 재발송 처리하는 최말단 기술 조직입니다. 알림 발송 실패 원인 진단, 누락된 알림의 재전송, 알림 전달 경로 모니터링 등을 통해 고객이 중요한 금융 정보를 놓치지 않도록 보장합니다.', ARRAY['알림누락', '푸시누락', '알림안옴', '알림지연', '재발송처리'], '푸시 알림이 오지 않음, 알림 지연, 알림 재발송 요청 등 알림 누락 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-2-1-1-1', '오류처리셀', '즉시이체 과정에서 발생하는 시스템 오류를 전문적으로 진단하고 해결하는 최말단 기술 조직입니다. 이체 중단 원인 분석, 오류 코드 해석, 시스템 장애 복구, 이체 재처리 등을 통해 고객의 즉시이체가 안전하고 확실하게 완료되도록 합니다.', ARRAY['이체오류', '즉시이체오류', '이체중단', '오류코드', '장애복구'], '즉시이체 중 발생하는 시스템 오류, 이체 중단, 오류 메시지 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-2-2-1-1', '실행모니터링셀', '예약이체의 실행 상태를 전문적으로 모니터링하고 이상 징후를 감지하는 최말단 운영 조직입니다. 예약된 이체의 실행 시점 모니터링, 미실행 케이스 발견 및 처리, 실행 오류 분석 등을 통해 고객의 예약이체가 정확한 시점에 확실하게 실행되도록 보장합니다.', ARRAY['예약이체실행', '예약이체모니터링', '예약이체미실행', '실행상태관리'], '예약이체 미실행, 실행 지연, 실행 오류 등 예약이체 실행 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('1-3-1-1-1', '네비게이션셀', '모바일 앱의 메뉴 이동 경로를 전문적으로 최적화하고 사용성을 개선하는 최말단 UX 조직입니다. 사용자 동선 분석, 메뉴 접근성 개선, 이동 경로 단축, 사용 패턴 기반 메뉴 재배치 등을 통해 고객이 원하는 기능에 최소한의 클릭으로 도달할 수 있도록 합니다.', ARRAY['네비게이션', '메뉴이동', '메뉴찾기', '이동경로', '사용자동선'], '메뉴를 찾기 어려움, 이동 경로가 복잡함, 버튼 위치 불편 등 앱 네비게이션 관련 사용성 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('2', '결제플랫폼본부', '공과금, 세금, 각종 요금 결제 등 Non-Banking 결제 서비스 전반을 총괄하는 조직입니다. 전통적인 계좌이체를 넘어서 생활밀착형 결제 생태계 구축과 외부 기관과의 결제 연동을 책임집니다. 전기료, 가스료, 수도료, 통신료, 보험료 등 일상생활에 필요한 모든 요금 납부를 원스톱으로 처리할 수 있는 플랫폼을 운영하며, 고객의 편의성과 결제 안정성을 보장합니다.', ARRAY['공과금', '세금', '요금결제', '납부', '결제', '요금', '전기료', '가스료', '수도료', '통신료', '보험료', '외부기관연동', '결제플랫폼'], '공과금 납부 관련 모든 이슈, 요금 결제 시스템 문제, 외부 기관과의 연동 오류, 납부 확인서 발급 등 결제 플랫폼 전반의 문제들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 결제 플랫폼 정책이나 전반적인 시스템 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('2-1', '공과금서비스부', '전기, 가스, 수도, 통신비 등 각종 공과금 납부 서비스를 기획하고 운영하는 조직입니다. 외부 기관(한국전력, 가스공사, 수자원공사, 통신사 등)과의 시스템 연동 및 결제 프로세스 최적화를 담당하며, 고객이 편리하게 모든 공과금을 한 곳에서 납부할 수 있는 통합 서비스를 제공합니다. 공과금 서비스의 기획부터 운영까지 전반적인 업무를 책임집니다.', ARRAY['공과금', '전기료', '가스료', '수도료', '통신료', '납부', '외부연동', '통합서비스', '서비스기획'], '공과금 서비스 전반의 정책, 외부 기관 연동 상태, 납부 프로세스 기획 등 공과금 서비스 부서 레벨의 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('2-2', '납부처리팀', '공과금 납부 거래의 실제 처리 로직을 담당하는 핵심 실무팀입니다. 결제 요청부터 완료까지의 전 과정을 모니터링하고, 납부 실패나 오류 발생 시 원인 분석 및 해결책을 제시합니다. 외부 기관과의 실시간 데이터 연동, 납부 상태 추적, 영수증 발급 등 납부와 관련된 모든 기술적 프로세스를 직접 관리합니다.', ARRAY['납부처리', '결제로직', '거래처리', '오류분석', '실패처리', '영수증발급', '실시간연동'], '납부 처리 시스템, 결제 로직, 처리 성능, 거래 오류 등 납부 처리 실무에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('2-3', '오류정정파트', '납부 과정에서 발생한 오류들을 체계적으로 분류하고 정정 작업을 수행하는 전문 조직입니다. 중복납부, 납부 실패, 금액 오류 등 다양한 예외 상황에 대한 표준 처리 프로세스를 운영하며, 고객과 외부 기관 간의 납부 상태 불일치 문제를 해결합니다. 결제 플랫폼의 신뢰성을 유지하는 핵심 역할을 담당합니다.', ARRAY['오류정정', '중복납부', '납부실패', '금액오류', '예외처리', '환불', '상태불일치', '정정프로세스'], '납부 오류 정정 프로세스, 중복 납부 처리, 환불 절차, 예외 상황 처리 등 오류 정정 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('2-4', '미납정정셀', '정상적으로 납부가 완료되었음에도 불구하고 미납으로 표시되는 시스템 오류를 전문적으로 해결하는 조직입니다. 외부 기관과의 데이터 동기화 문제를 진단하고 납부 상태를 정정하며, 고객이 납부 확인서를 제시했을 때 시스템 상의 미납 상태를 즉시 수정합니다. 가장 빈발하는 납부 관련 문제를 전담하여 처리하는 전문 셀입니다.', ARRAY['미납정정', '납부상태', '동기화오류', '외부기관연동', '데이터정합성', '납부확인서', '상태수정'], '납부했는데 미납으로 표시, 납부 확인서 있는데 시스템 미납, 외부 기관과의 상태 불일치 등 미납 정정 관련 모든 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3', '외환사업본부', '외화 관련 모든 업무를 총괄하는 조직입니다. 환전, 해외송금, 외화예금, 환율 정보 제공 등 국경을 넘나드는 금융 서비스를 책임지며, 글로벌 금융 시장과의 연결고리 역할을 수행합니다. 개인 고객의 해외여행, 유학, 해외거주부터 기업의 수출입 업무까지 다양한 외화 니즈를 충족시키며, 외환 시장의 변동성에 대응하는 리스크 관리도 담당합니다.', ARRAY['외화', '환전', '해외송금', '환율', '달러', '유로', '엔', '외화예금', '해외여행', '유학', '해외거주', '글로벌금융', '외환리스크'], '외화 서비스 전반의 정책, 환율 정보, 해외 금융 서비스 등 외환 업무 전반에 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 외환 정책이나 전반적인 외화 서비스 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3-1', '외화채널부', '고객이 외화 서비스를 이용할 수 있는 모든 채널(앱, 인터넷, 영업점)을 관리하고, 외화 거래의 사용자 경험을 개선하는 조직입니다. 외화 거래 프로세스 설계, 환율 정보 표시 방식, 외화 상품 안내 등을 통해 고객이 편리하고 안전하게 외화 거래를 할 수 있는 환경을 조성합니다. 외화 서비스의 채널 전략과 운영을 담당합니다.', ARRAY['외화거래', '환전신청', '외화채널', '해외송금채널', '외화상품', '거래프로세스', '채널전략'], '외화 거래 채널, 사용자 경험, 외화 상품 안내 등 외화 채널 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3-2', '환전서비스팀', '원화와 외화 간 환전 서비스를 전담하여 운영하는 조직입니다. 실시간 환율 정보 제공, 환전 신청 처리, 환전 한도 관리 등을 담당하며, 고객이 필요한 외화를 적정한 환율로 교환할 수 있도록 지원합니다. 다양한 통화별 환전 서비스와 환전 우대 혜택 관리도 포함합니다.', ARRAY['환전', '환율', '실시간환율', '환전신청', '환전한도', '통화별환전', '환전우대', '환전서비스'], '환전 서비스 전반, 환율 정책, 환전 한도, 환전 프로세스 등 환전 서비스에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3-3', '해외송금운영파트', '해외로 돈을 보내거나 받는 송금 서비스를 전담하여 운영하는 조직입니다. 송금 신청부터 완료까지의 전 과정을 모니터링하고 오류를 해결하며, 국제 송금 네트워크(SWIFT 등)와의 연동을 관리합니다. 송금 수수료, 송금 한도, 송금 규정 준수 등도 담당하는 해외송금 전문 조직입니다.', ARRAY['해외송금', '송금신청', '송금오류', '송금지연', '수수료', '송금한도', 'SWIFT', '국제송금네트워크', '송금운영'], '해외송금 서비스 전반, 송금 프로세스, 송금 정책, 송금 운영 등 해외송금에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3-2-1', '환율관리파트', '국제금융시장의 환율 변동을 실시간으로 모니터링하고, 고객에게 정확한 환율 정보를 제공하는 전문 조직입니다. 글로벌 외환시장 데이터 수집, 환율 산정 로직 관리, 환율 변동 알림 서비스 등을 통해 투명하고 신뢰할 수 있는 환율 정보를 제공합니다. 환전 서비스의 핵심 기반이 되는 환율 관리를 담당합니다.', ARRAY['환율관리', '환율정보', '환율변동', '실시간환율', '글로벌외환시장', '환율산정로직', '환율모니터링'], '환율 관리 시스템, 환율 정보 제공, 환율 산정 등 환율 관리 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3-3-1', '송금오류처리셀', '해외송금 과정에서 발생하는 모든 오류를 전문적으로 해결하는 최말단 기술 조직입니다. 송금 중단, 수취인 정보 오류, 중계은행 문제 등을 진단하고 처리하며, 국제 송금 네트워크의 복잡한 경로에서 발생할 수 있는 다양한 기술적 문제를 즉시 해결합니다. 해외송금의 안정성을 보장하는 핵심 역할을 담당합니다.', ARRAY['송금오류', '송금중단', '수취인오류', '중계은행', '송금실패', '국제송금네트워크오류', '오류해결'], '해외송금 중단, 송금이 도착하지 않음, 송금 에러코드 발생 등 해외송금 과정의 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('3-2-1-1', '실시간환율셀', '글로벌 외환시장 데이터를 실시간으로 수집하여 시스템에 반영하고, 환율 지연이나 오류를 즉시 감지하여 해결하는 최말단 기술 조직입니다. 환율 피드 연동, 데이터 검증, 환율 업데이트 모니터링 등을 통해 고객이 항상 최신 환율 정보를 확인할 수 있도록 보장합니다. 환전 서비스의 신뢰성을 뒷받침하는 핵심 기술 조직입니다.', ARRAY['실시간환율', '환율지연', '환율오류', '환율반영', '환율피드연동', '데이터검증', '환율업데이트'], '환율이 실시간으로 반영 안됨, 환율 정보가 지연됨, 다른 곳과 환율이 다름 등 실시간 환율 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('4', '상품기획본부', '은행의 모든 금융상품을 기획하고 설계하는 조직입니다. 예금, 적금, 대출, 투자상품 등 고객의 다양한 금융 니즈를 충족시킬 수 있는 혁신적이고 경쟁력 있는 상품을 개발합니다. 시장 분석, 고객 요구 분석, 상품 수익성 분석 등을 통해 최적의 상품 포트폴리오를 구성하며, 상품의 생명주기 전반을 관리합니다.', ARRAY['상품기획', '예금', '적금', '대출상품', '투자상품', '금융상품설계', '상품개발', '시장분석', '상품포트폴리오'], '금융상품 전반의 기획, 새로운 상품 요청, 기존 상품 개선 제안 등 상품 기획과 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 상품 전략이나 전반적인 상품 정책 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('4-1', '예적금상품부', '예금과 적금 상품을 전문적으로 기획하고 관리하는 조직입니다. 정기예금, 적금, 특판상품 등의 기초 설계, 금리 정책 수립, 상품 생명주기 관리를 담당하며, 고객의 자산 증식 목표에 맞는 다양한 예적금 상품을 제공합니다. 예적금 상품 전반의 기획과 운영 정책을 책임집니다.', ARRAY['예적금', '정기예금', '적금', '특판상품', '금리정책', '상품생명주기', '자산증식', '상품기획'], '예적금 상품 기획, 금리 정책, 상품 조건 등 예적금 상품 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('4-2', '상품설계팀', '예적금 상품의 구체적인 설계와 상품 명세서 작성을 담당하는 전문팀입니다. 상품 조건, 가입 대상, 만기 구조, 중도해지 조건 등을 설계하고, 법규 준수 여부를 검토하며, 상품의 경쟁력을 분석합니다. 고객이 이해하기 쉽고 매력적인 상품을 만들기 위한 상세 설계를 담당합니다.', ARRAY['상품설계', '상품명세서', '상품조건', '가입대상', '만기구조', '중도해지', '법규준수', '경쟁력분석'], '상품 설계 로직, 상품 조건, 상품 구조, 법규 준수 등 상품 설계 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('4-3', '상품안내파트', '예적금 상품에 대한 고객 안내 자료와 설명 콘텐츠를 기획하고 관리하는 전문 조직입니다. 상품 설명서, 약관, FAQ, 가입 안내 등의 기획과 관리를 담당하며, 고객이 상품을 정확히 이해하고 적절한 선택을 할 수 있도록 돕는 모든 정보 제공 업무를 책임집니다.', ARRAY['상품안내', '상품설명서', '약관', 'FAQ', '가입안내', '고객정보제공', '안내자료기획'], '상품 안내 자료, 설명 부족, 약관 이해, 가입 안내 등 상품 안내 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('4-4', '안내콘텐츠셀', '예적금 상품의 안내 콘텐츠를 전문적으로 제작하고 관리하는 최말단 콘텐츠 조직입니다. 상품별 상세 설명, 가입 조건 안내, 혜택 설명, 주의사항 등을 고객이 이해하기 쉽게 작성하고, 지속적으로 업데이트하여 정확한 정보를 제공합니다. 상품 안내의 실질적인 콘텐츠 제작을 담당하는 전문 셀입니다.', ARRAY['안내콘텐츠', '상품설명', '가입조건안내', '혜택설명', '주의사항', '콘텐츠업데이트', '콘텐츠제작'], '상품 설명 부족, 가입 조건 불명확, 혜택 안내 부족, 콘텐츠 오류 등 상품 안내 콘텐츠 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('5', '여신심사본부', '모든 대출 상품의 심사와 승인을 담당하는 조직입니다. 개인신용대출, 주택담보대출, 기업대출 등 다양한 여신 상품의 신청을 검토하고, 고객의 신용도와 상환능력을 평가하여 대출 승인 여부를 결정합니다. 리스크 관리와 건전한 여신 운용을 통해 은행의 자산 건전성을 보호하며, 특히 비대면 디지털 채널을 통한 대출 심사 혁신을 주도합니다.', ARRAY['여신심사', '대출심사', '신용평가', '상환능력평가', '리스크관리', '자산건전성', '개인신용대출', '주택담보대출', '비대면심사'], '대출 심사 과정, 심사 기준, 승인/거부 사유, 심사 소요 시간 등 여신 심사 전반에 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 심사 정책이나 전반적인 심사 프로세스 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('5-1', '비대면여신심사부', '온라인과 모바일을 통한 비대면 대출 신청의 심사를 전담하는 조직입니다. 디지털 채널로 접수된 대출 신청을 신속하고 정확하게 심사하며, 자동화된 심사 시스템과 인공지능을 활용한 신용평가를 통해 빠른 대출 승인 서비스를 제공합니다. 기존 대면 심사와 차별화된 디지털 심사 프로세스를 설계하고 운영합니다.', ARRAY['비대면대출심사', '온라인대출', '모바일대출', '자동화심사', 'AI신용평가', '신속승인', '디지털심사프로세스'], '비대면 대출 심사 프로세스 전반, 자동화 심사 시스템, 신속 승인 정책 등 비대면 여신 심사 부서 레벨의 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('5-2', '비대면대출심사팀', '비대면 채널로 접수된 대출 신청의 실제 심사 업무를 수행하는 실무팀입니다. 신용정보 조회, 소득 확인, 담보 평가 등을 통해 고객의 신용도와 상환능력을 종합적으로 평가하고, 적정 대출 한도와 금리를 산정하여 승인 여부를 결정합니다. 개별 대출 건별 심사를 담당하는 핵심 실무 조직입니다.', ARRAY['대출심사', '신용정보조회', '소득확인', '담보평가', '신용도평가', '대출한도산정', '금리산정', '승인결정'], '개별 대출 심사 과정, 심사 기준 적용, 한도 산정, 금리 결정 등 구체적인 대출 심사 업무에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('5-3', '심사운영파트', '대출 심사 프로세스의 운영과 관리를 전담하는 조직입니다. 심사 절차 표준화, 심사 시간 관리, 심사 품질 관리, 고객 응대 등을 통해 효율적이고 일관성 있는 심사 업무가 이루어지도록 지원합니다. 심사 업무의 백오피스 역할을 담당하며, 심사 프로세스 개선과 최적화를 추진합니다.', ARRAY['심사운영', '심사절차표준화', '심사시간관리', '심사품질관리', '프로세스개선', '고객응대'], '심사 프로세스 운영, 심사 절차, 심사 소요 시간, 품질 관리 등 심사 운영 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('5-4', '서류검증셀', '대출 신청 시 제출된 서류들의 진위 여부와 유효성을 전문적으로 검증하는 조직입니다. 소득증빙서류, 재직증명서, 신분증 등의 위변조 여부를 확인하고, 서류의 완전성과 정확성을 검토하여 신뢰할 수 있는 심사 자료를 확보합니다. 심사의 첫 단계이자 가장 중요한 기초 작업을 담당합니다.', ARRAY['서류검증', '위변조확인', '소득증빙서류', '재직증명서', '신분증검증', '서류완전성검토', '진위확인'], '서류 검증 실패, 서류 재제출 요청, 서류 유효성 문제, 위변조 의심 등 서류 검증 관련 모든 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('6', '카드사업본부', '신용카드, 체크카드, 법인카드 등 모든 카드 상품과 서비스를 총괄하는 조직입니다. 카드 발급부터 이용, 결제, 혜택 제공까지 카드 생명주기 전반을 관리하며, 고객의 일상 결제와 금융 편의를 위한 혁신적인 카드 서비스를 제공합니다. 카드 시장의 경쟁력 강화와 디지털 카드 서비스 확산을 주도합니다.', ARRAY['카드사업', '신용카드', '체크카드', '법인카드', '카드발급', '카드결제', '카드혜택', '디지털카드', '카드서비스'], '카드 사업 전반의 정책, 카드 상품 기획, 카드 서비스 전략 등 카드 사업과 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 카드 사업 정책이나 전반적인 카드 서비스 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('6-1', '디지털카드부', '디지털 환경에서의 카드 서비스를 전담하여 기획하고 운영하는 조직입니다. 모바일 카드, 디지털 월렛 연동, 온라인 카드 발급, 비접촉 결제 등 디지털 기술을 활용한 혁신적인 카드 서비스를 제공합니다. 전통적인 플라스틱 카드를 넘어선 미래형 카드 서비스의 발전을 주도하며, 디지털 카드 생태계 구축을 담당합니다.', ARRAY['디지털카드', '모바일카드', '디지털월렛', '온라인발급', '비접촉결제', '혁신카드서비스', '디지털생태계'], '디지털 카드 서비스 전반, 모바일 카드 기능, 디지털 혁신 등 디지털 카드 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('6-2', '카드신청운영팀', '카드 신청부터 발급까지의 전 과정을 운영하고 관리하는 핵심 실무팀입니다. 카드 신청 접수, 심사 진행 관리, 고객 응대, 신청 상태 관리 등 카드 신청 프로세스의 운영적 측면을 담당합니다. 고객이 원활하게 카드를 신청하고 진행 상황을 확인할 수 있도록 하는 운영 업무를 책임집니다.', ARRAY['카드신청', '신청접수', '심사진행관리', '고객응대', '신청상태관리', '신청프로세스운영'], '카드 신청 프로세스, 신청 진행 상황, 신청 관련 문의 등 카드 신청 운영에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('6-3', '발급처리파트', '심사 완료된 카드의 실제 발급 처리를 전담하는 조직입니다. 카드 제작, 개인화 작업(이름, 번호 인쇄 등), 품질 검증, 발송 준비, 배송 관리 등 카드 발급의 실질적인 처리 과정을 관리합니다. 카드 발급의 정확성과 신속성을 보장하며, 고객이 신속하게 카드를 받을 수 있도록 하는 핵심 업무를 담당합니다.', ARRAY['발급처리', '카드제작', '개인화작업', '품질검증', '발송준비', '배송관리', '제작관리'], '카드 발급 처리, 제작 과정, 배송 관리, 발급 지연 등 발급 처리 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('6-4', '오류관리셀', '카드 신청, 심사, 발급 과정에서 발생하는 모든 오류를 전문적으로 관리하고 해결하는 조직입니다. 신청서 오류, 심사 시스템 오류, 발급 처리 오류, 카드 제작 오류 등을 즉시 감지하고 수정하여 고객이 원활하게 카드를 발급받을 수 있도록 보장합니다. 카드 발급 프로세스 전체의 안정성과 신뢰성을 책임지는 전문 조직입니다.', ARRAY['오류관리', '신청서오류', '심사시스템오류', '발급처리오류', '카드제작오류', '오류해결', '프로세스안정성'], '카드 신청이 진행되지 않음, 발급 처리 중 오류 발생, 카드 제작 문제, 시스템 오류 등 카드 관련 모든 오류를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7', '정보보호본부', '은행의 모든 정보 보안과 고객 인증 시스템을 총괄하는 조직입니다. 사이버 보안, 개인정보 보호, 인증 시스템 구축 및 운영을 통해 고객의 금융 정보와 자산을 안전하게 보호합니다. 해킹, 금융사기, 개인정보 유출 등 다양한 보안 위협으로부터 은행과 고객을 보호하며, 안전한 금융 서비스 환경을 조성합니다.', ARRAY['정보보호', '사이버보안', '개인정보보호', '인증시스템', '보안위협', '금융보안', '해킹방지', '사기방지'], '보안 정책, 인증 시스템 전반, 개인정보 보호 등 정보보호와 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 보안 정책이나 전반적인 보안 시스템 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-1', '인증보안부', '고객 인증과 관련된 보안 정책과 전략을 수립하고 관리하는 조직입니다. 다양한 인증 수단(OTP, 생체인증, 공동인증서)의 통합 관리, 인증 보안 정책 수립, 인증 기술 발전 방향 설정 등을 담당합니다. 인증 시스템 전반의 보안 수준을 향상시키고 일관된 보안 정책을 유지하는 역할을 수행합니다.', ARRAY['인증보안정책', '인증전략', '보안정책수립', '인증기술발전', '통합인증관리'], '인증 보안 정책, 인증 전략, 보안 기준 등 인증 보안 전반에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-2', 'OTP관리팀', 'OTP(One Time Password) 인증 시스템을 전담하여 운영하고 관리하는 팀입니다. OTP 토큰 발급, OTP 앱 관리, 인증번호 생성 알고리즘 운영 등을 담당하며, 고객이 안전하고 편리하게 OTP 인증을 이용할 수 있도록 지원합니다. OTP 시스템의 안정성과 보안성을 지속적으로 강화합니다.', ARRAY['OTP관리', 'OTP토큰', 'OTP앱', '인증번호생성', '일회용비밀번호', 'OTP시스템'], 'OTP 시스템 전반, OTP 발급, OTP 앱 관리 등 OTP 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-3', '생체인증개발팀', '지문, 얼굴, 홍채 등 생체정보를 활용한 인증 시스템을 개발하고 운영하는 팀입니다. 생체인증 기술 연구, 인증 알고리즘 개발, 생체정보 보안 관리 등을 담당하며, 차세대 인증 기술을 통해 더욱 안전하고 편리한 인증 서비스를 제공합니다. 생체인증 기술의 지속적인 발전과 보안 강화를 주도합니다.', ARRAY['생체인증', '지문인증', '얼굴인증', '홍채인증', '생체정보보안', '인증알고리즘개발'], '생체인증 기술, 인증 개발, 생체정보 보안 등 생체인증에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-4', '인증서관리팀', '공동인증서(구 공인인증서) 및 기타 디지털 인증서의 발급, 관리, 갱신을 담당하는 팀입니다. 인증서 생명주기 전반을 관리하고, 인증서 보안 정책을 수립하며, 고객이 안전하게 인증서를 이용할 수 있도록 지원합니다. 인증서 기술 발전에 따른 시스템 개선과 보안 강화도 담당합니다.', ARRAY['인증서관리', '공동인증서', '디지털인증서', '인증서발급', '인증서갱신', '인증서보안'], '인증서 시스템 전반, 인증서 발급, 갱신, 관리 정책 등 인증서 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-5', '인증서오류분석파트', '인증서 시스템에서 발생하는 각종 오류를 전문적으로 분석하고 해결하는 조직입니다. 인증서 발급 오류, 갱신 실패, 인증서 인식 문제 등을 체계적으로 분석하여 인증서 시스템의 안정성과 신뢰성을 보장합니다. 인증서 관련 기술적 문제의 전문 분석과 해결을 담당합니다.', ARRAY['인증서오류분석', '발급오류', '갱신실패', '인증서인식문제', '기술분석'], '인증서 오류 분석, 발급 실패 원인 파악, 기술적 문제 해결 등 인증서 오류 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-6', '등록오류셀', '인증서 등록 과정에서 발생하는 기술적 오류를 전문적으로 해결하는 조직입니다. 인증서 등록 실패, 갱신 오류, 인증서 파일 손상 등을 즉시 진단하고 해결하여 고객이 원활하게 인증서를 등록하고 이용할 수 있도록 보장합니다. 인증서 등록 관련 모든 기술적 문제를 전문적으로 처리합니다.', ARRAY['등록오류', '인증서등록실패', '갱신오류', '인증서파일손상', '등록프로세스오류'], '공동인증서가 등록이 안됨, 인증서 갱신 실패, 인증서 파일 오류 등 인증서 등록 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-2-1', 'OTP오류분석파트', 'OTP 시스템에서 발생하는 각종 오류를 전문적으로 분석하고 해결하는 조직입니다. OTP 생성 오류, 인증 실패, 토큰 동기화 문제 등을 체계적으로 분석하여 원인을 파악하고 해결 방안을 제시합니다. OTP 시스템의 안정성과 신뢰성을 보장하는 핵심 역할을 담당합니다.', ARRAY['OTP오류분석', '인증실패분석', '토큰동기화', 'OTP생성오류', '시스템분석'], 'OTP 오류 분석, 인증 실패 원인 파악 등 OTP 오류 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-3-1', '인증오류분석파트', '생체인증 시스템에서 발생하는 각종 오류를 전문적으로 분석하고 해결하는 조직입니다. 생체정보 인식 실패, 인증 알고리즘 오류, 생체 데이터 처리 문제 등을 체계적으로 분석하여 생체인증 시스템의 정확성과 안정성을 향상시킵니다.', ARRAY['생체인증오류분석', '인식실패분석', '알고리즘오류', '생체데이터처리'], '생체인증 오류 분석, 인식 실패 원인 파악 등 생체인증 오류 관련 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-2-1-1', '인증실행셀', 'OTP 인증의 실제 실행 과정에서 발생하는 기술적 문제를 전문적으로 해결하는 최말단 기술 조직입니다. OTP 인증번호 입력 오류, 인증 시간 초과, 시스템 동기화 문제 등을 즉시 진단하고 해결하여 고객이 원활하게 OTP 인증을 완료할 수 있도록 보장합니다.', ARRAY['인증실행', 'OTP입력오류', '인증시간초과', '시스템동기화', '실행오류해결'], 'OTP 입력해도 로그인 안됨, 인증 시간 초과, OTP 동기화 문제 등 OTP 실행 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('7-3-1-1', '생체오류셀', '생체인증 과정에서 발생하는 기술적 오류를 전문적으로 해결하는 최말단 기술 조직입니다. 지문 인식 실패, 얼굴 인증 오류, 생체정보 매칭 실패 등을 즉시 진단하고 해결하여 고객이 원활하게 생체인증을 이용할 수 있도록 보장합니다.', ARRAY['생체오류', '지문인식실패', '얼굴인증오류', '생체정보매칭실패', '생체인식오류'], '지문인식이 계속 실패, 얼굴인증이 안됨, 생체인증 오류 등 생체인증 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8', 'IT인프라본부', '은행의 모든 IT 시스템과 인프라를 총괄하여 안정적이고 효율적인 IT 서비스를 제공하는 조직입니다. 서버, 네트워크, 데이터베이스 등 핵심 인프라의 구축과 운영, 시스템 장애 대응, 성능 최적화를 담당하며, 디지털 금융 서비스의 기술적 기반을 제공합니다. IT 시스템의 안정성과 보안성을 보장하여 고객이 언제든지 신뢰할 수 있는 금융 서비스를 이용할 수 있도록 지원합니다.', ARRAY['IT인프라', '시스템운영', '서버관리', '네트워크', '데이터베이스', '장애대응', '성능최적화', '기술인프라'], 'IT 시스템 전반의 성능, 인프라 정책, 기술 전략 등 IT 인프라와 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 IT 전략이나 전반적인 시스템 정책 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-1', '시스템운영부', '은행의 핵심 IT 시스템과 서버 인프라의 운영과 관리를 전담하는 조직입니다. 24시간 시스템 모니터링, 서버 성능 관리, 장애 예방 및 대응을 담당하며, 안정적인 IT 서비스 제공을 위한 운영 체계를 구축하고 관리합니다. 시스템의 가용성과 성능을 최적화하여 고객 서비스 중단을 방지합니다.', ARRAY['시스템운영', '서버관리', '24시간모니터링', '성능관리', '가용성관리', '운영체계'], '시스템 운영 전반, 서버 성능, 시스템 안정성 등 시스템 운영에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-2', '서비스운영부', 'IT 서비스의 운영과 고객 커뮤니케이션을 담당하는 조직입니다. 시스템 점검 계획 수립, 서비스 중단 공지, 고객 안내 등을 통해 IT 서비스 운영의 투명성과 예측 가능성을 제공합니다. 고객이 IT 서비스 변화를 미리 인지하고 대비할 수 있도록 효과적인 커뮤니케이션을 담당합니다.', ARRAY['서비스운영', '시스템점검', '서비스공지', '고객커뮤니케이션', '운영투명성'], '서비스 운영 전반, 점검 계획, 고객 안내 등 서비스 운영에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-3', '모바일앱QA부', '모바일 애플리케이션의 품질 보증(Quality Assurance)을 전담하는 조직입니다. 앱 기능 테스트, 성능 테스트, 사용성 테스트, 보안 테스트 등을 통해 모바일 앱의 품질을 보장합니다. 앱 출시 전 철저한 검증을 통해 고객에게 안정적이고 우수한 품질의 모바일 서비스를 제공합니다.', ARRAY['모바일앱QA', '품질보증', '앱테스트', '성능테스트', '사용성테스트', '품질검증'], '모바일 앱 품질, 테스트 프로세스, 품질 기준 등 모바일 앱 QA에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-4', '버전호환성테스트팀', '모바일 앱과 시스템의 버전 호환성을 전문적으로 테스트하고 검증하는 팀입니다. 새로운 앱 버전과 기존 시스템 간의 호환성, 다양한 운영체제 버전과의 호환성, 업데이트 과정의 안정성 등을 테스트하여 버전 변경으로 인한 서비스 중단이나 오류를 방지합니다.', ARRAY['버전호환성', '호환성테스트', '앱버전', '시스템호환성', '업데이트테스트'], '버전 호환성, 업데이트 문제, 호환성 테스트 등 버전 호환성에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-5', '호환성분석파트', '시스템과 애플리케이션의 호환성 문제를 전문적으로 분석하는 조직입니다. 호환성 이슈의 원인 분석, 해결 방안 도출, 호환성 개선 방향 제시 등을 담당하며, 다양한 환경에서 안정적으로 작동하는 시스템 구축에 기여합니다.', ARRAY['호환성분석', '이슈분석', '해결방안도출', '호환성개선', '환경분석'], '호환성 분석, 호환성 문제 해결, 개선 방안 등 호환성 분석에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-6', '구형기기셀', '구형 기기와 레거시 시스템의 호환성을 전문적으로 관리하는 조직입니다. 오래된 스마트폰, 구형 운영체제, 레거시 시스템에서도 금융 서비스를 안정적으로 이용할 수 있도록 지원하며, 디지털 소외 계층을 위한 기술적 솔루션을 제공합니다.', ARRAY['구형기기', '레거시시스템', '구형운영체제', '디지털소외', '하위호환성'], '구형 기기 지원, 레거시 시스템 호환성, 하위 호환성 등 구형 기기 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-1-1', '앱플랫폼운영팀', '모바일 앱 플랫폼의 운영과 관리를 전담하는 팀입니다. 앱 서버 운영, API 관리, 앱 성능 모니터링, 트래픽 관리 등을 담당하며, 모바일 앱이 안정적으로 작동할 수 있는 플랫폼 환경을 제공합니다. 앱 플랫폼의 가용성과 성능을 최적화합니다.', ARRAY['앱플랫폼운영', '앱서버', 'API관리', '성능모니터링', '트래픽관리'], '앱 플랫폼 운영, 서버 성능, API 관리 등 앱 플랫폼에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-2-1', '공지관리팀', 'IT 서비스 관련 모든 공지사항의 관리를 전담하는 팀입니다. 시스템 점검 공지, 서비스 중단 안내, 업데이트 공지 등을 기획하고 관리하며, 고객이 IT 서비스 변화를 미리 인지할 수 있도록 효과적인 커뮤니케이션을 제공합니다.', ARRAY['공지관리', '시스템점검공지', '서비스중단안내', '업데이트공지', '고객커뮤니케이션'], '공지 관리, 고객 안내, 커뮤니케이션 등 공지 관리에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-1-1-1', '장애대응파트', '앱 플랫폼에서 발생하는 장애를 신속하게 대응하고 해결하는 전문 조직입니다. 장애 감지, 원인 분석, 복구 작업, 재발 방지 대책 수립 등을 담당하며, 장애로 인한 서비스 중단 시간을 최소화합니다. 24시간 장애 대응 체계를 운영합니다.', ARRAY['장애대응', '장애감지', '원인분석', '복구작업', '재발방지', '24시간대응'], '장애 대응, 복구 작업, 장애 예방 등 장애 대응에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-2-1-1', '점검공지파트', '시스템 점검과 관련된 공지사항을 전문적으로 관리하는 조직입니다. 점검 계획 수립, 점검 영향도 분석, 고객 공지 작성, 점검 일정 관리 등을 담당하며, 고객이 점검으로 인한 서비스 중단을 미리 인지하고 대비할 수 있도록 합니다.', ARRAY['점검공지', '점검계획', '영향도분석', '일정관리', '고객안내'], '점검 공지, 점검 계획, 고객 안내 등 점검 공지에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-1-1-1-1', '서버모니터링셀', '앱 플랫폼의 서버 상태를 24시간 실시간으로 모니터링하는 최말단 기술 조직입니다. 서버 성능 지표 감시, 리소스 사용량 추적, 이상 징후 감지, 알림 발송 등을 통해 장애를 사전에 예방하고 신속한 대응이 가능하도록 지원합니다.', ARRAY['서버모니터링', '실시간감시', '성능지표', '리소스사용량', '이상징후감지', '24시간모니터링'], '앱이 자꾸 멈춤, 로딩이 너무 느림, 서버 접속 불가 등 서버 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('8-2-1-1-1', '공지등록셀', '시스템 점검 및 서비스 공지사항을 실제로 등록하고 관리하는 최말단 실무 조직입니다. 공지사항 작성, 발송 시점 관리, 공지 채널 선택, 공지 효과 추적 등을 통해 고객에게 정확하고 시의적절한 정보를 제공합니다.', ARRAY['공지등록', '공지작성', '발송시점관리', '공지채널', '효과추적'], '점검 안내도 없이 접속이 안됨, 공지가 늦게 올라옴, 공지 내용이 부정확함 등 공지 등록 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9', '디지털혁신본부', '은행의 디지털 혁신과 신기술 도입을 주도하는 조직입니다. AI, 빅데이터, 블록체인 등 첨단 기술을 활용한 혁신적인 금융 서비스를 기획하고 개발하며, 고객의 변화하는 니즈에 맞는 새로운 서비스를 지속적으로 발굴합니다. 디지털 트랜스포메이션을 통해 은행의 경쟁력을 강화하고 미래 금융 생태계를 선도합니다.', ARRAY['디지털혁신', '신기술도입', 'AI', '빅데이터', '블록체인', '혁신서비스', '디지털트랜스포메이션', '미래금융'], '디지털 혁신 전략, 신기술 도입, 혁신 서비스 기획 등 디지털 혁신과 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 혁신 전략이나 전반적인 디지털 혁신 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-1', 'AI플랫폼부', '인공지능 기술을 활용한 금융 서비스 플랫폼을 구축하고 운영하는 조직입니다. AI 기반 고객 상담, 자동화된 금융 상품 추천, 리스크 관리, 사기 탐지 등 다양한 AI 서비스를 개발하고 관리합니다. AI 기술의 금융 분야 적용을 선도하며, 고객에게 더욱 스마트하고 개인화된 금융 서비스를 제공합니다.', ARRAY['AI플랫폼', '인공지능', '자동화서비스', '개인화추천', 'AI상담', '사기탐지', '스마트금융'], 'AI 플랫폼 전반, 인공지능 서비스, AI 기술 등 AI 플랫폼에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-2', '서비스기획부', '새로운 디지털 금융 서비스의 기획과 전략 수립을 담당하는 조직입니다. 시장 트렌드 분석, 고객 니즈 조사, 경쟁사 분석을 통해 혁신적인 서비스 아이디어를 발굴하고, 사업성과 실현 가능성을 검토하여 새로운 서비스 론칭을 주도합니다. 디지털 서비스 혁신의 기획 단계를 총괄합니다.', ARRAY['서비스기획', '신규서비스', '시장분석', '고객니즈조사', '혁신아이디어', '사업성검토'], '서비스 기획, 혁신 아이디어, 신규 서비스 전략 등 서비스 기획에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-3', '신규서비스기획팀', '구체적인 신규 서비스의 기획과 개발을 전담하는 팀입니다. 서비스 컨셉 설계, 기능 명세 작성, 개발 로드맵 수립, 출시 전략 기획 등을 담당하며, 아이디어 단계부터 실제 서비스 출시까지의 전 과정을 관리합니다. 혁신적인 금융 서비스의 구체화와 실현을 책임집니다.', ARRAY['신규서비스기획', '서비스컨셉', '기능명세', '개발로드맵', '출시전략', '서비스구체화'], '신규 서비스 기획, 서비스 개발, 출시 계획 등 신규 서비스에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-4', '제안반영파트', '고객과 내부 직원으로부터 접수된 서비스 개선 제안과 아이디어를 체계적으로 관리하고 반영하는 조직입니다. 제안 접수, 검토, 평가, 반영 여부 결정, 피드백 제공 등을 담당하며, 지속적인 서비스 개선과 혁신을 위한 아이디어 관리 체계를 운영합니다.', ARRAY['제안반영', '아이디어관리', '서비스개선제안', '고객제안', '직원제안', '피드백제공'], '서비스 개선 제안, 아이디어 반영, 제안 관리 등 제안 반영에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-5', '기능검토셀', '새로운 기능과 서비스의 기술적 검토와 타당성 분석을 전문적으로 수행하는 조직입니다. 기술적 구현 가능성, 시스템 영향도, 개발 비용, 보안 위험 등을 종합적으로 검토하여 새로운 기능 도입의 타당성을 평가합니다. 혁신과 안정성의 균형을 유지하는 핵심 역할을 담당합니다.', ARRAY['기능검토', '기술검토', '타당성분석', '구현가능성', '시스템영향도', '보안위험평가'], '새로운 기능 요청, 기술적 검토, 구현 타당성 등 기능 검토에 관련된 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-1-1', '챗봇운영팀', 'AI 기반 챗봇 서비스의 운영과 관리를 전담하는 팀입니다. 챗봇 대화 시나리오 작성, 응답 정확도 향상, 자연어 처리 성능 개선, 고객 만족도 관리 등을 담당하며, 고객이 편리하고 정확한 AI 상담 서비스를 이용할 수 있도록 지원합니다. 챗봇 기술의 지속적인 발전을 주도합니다.', ARRAY['챗봇운영', 'AI상담', '대화시나리오', '자연어처리', '응답정확도', '고객만족도'], '챗봇 운영 전반, AI 상담 품질, 챗봇 기능 등 챗봇 운영에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-1-1-1', '응답품질관리파트', '챗봇의 응답 품질을 전문적으로 관리하고 개선하는 조직입니다. 챗봇 응답의 정확성, 적절성, 유용성을 지속적으로 모니터링하고, 오답 사례를 분석하여 개선 방안을 도출합니다. 고객이 만족할 수 있는 고품질의 AI 상담 서비스를 제공하기 위한 품질 관리를 담당합니다.', ARRAY['응답품질관리', '정확성모니터링', '적절성평가', '품질개선', '성능향상'], '챗봇 응답 품질, 품질 관리, 성능 개선 등 응답 품질에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('9-1-1-1-1', '오답분석셀', '챗봇이 제공한 잘못된 답변을 전문적으로 분석하고 개선하는 최말단 기술 조직입니다. 오답 사례 수집, 원인 분석, 학습 데이터 보완, 알고리즘 튜닝 등을 통해 챗봇의 응답 정확도를 지속적으로 향상시킵니다. AI 학습과 개선의 핵심 역할을 담당합니다.', ARRAY['오답분석', '사례수집', '원인분석', '학습데이터보완', '알고리즘튜닝', '정확도향상'], '챗봇이 계속 같은 말만 함, 챗봇 답변이 부정확함, 질문을 이해 못함 등 챗봇 오답 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10', '고객서비스본부', '모든 고객 접점에서의 서비스 품질과 고객 만족도를 총괄하는 조직입니다. 전화상담, 디지털상담, 고객불만 처리, 서비스 개선 등을 통해 고객의 목소리를 경청하고 최상의 고객 경험을 제공합니다. 고객 중심의 서비스 문화를 조성하고, 고객 피드백을 바탕으로 지속적인 서비스 품질 향상을 추진합니다.', ARRAY['고객서비스', '고객만족', '상담서비스', '고객불만처리', '서비스품질', '고객경험', '고객중심'], '고객 서비스 전반의 정책, 상담 서비스 품질, 고객 응대 등 고객 서비스와 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 고객 서비스 정책이나 전반적인 서비스 전략 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-1', '디지털상담센터', '디지털 채널을 통한 고객 상담 서비스를 전담하는 조직입니다. 챗봇 상담, 온라인 문의, 화상 상담 등 디지털 기술을 활용한 혁신적인 상담 서비스를 제공하며, 고객이 언제 어디서나 편리하게 상담을 받을 수 있는 환경을 조성합니다. 디지털 상담의 품질과 효율성을 지속적으로 개선합니다.', ARRAY['디지털상담', '챗봇상담', '온라인문의', '화상상담', '비대면상담', '디지털고객서비스'], '디지털 상담 서비스 전반, 챗봇 상담 품질, 온라인 문의 처리 등 디지털 상담에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-2', '콜센터운영부', '전화를 통한 고객 상담 서비스의 운영과 관리를 전담하는 조직입니다. 상담사 교육, 통화 품질 관리, 대기시간 단축, 상담 프로세스 개선 등을 담당하며, 고객이 신속하고 정확한 전화 상담을 받을 수 있도록 지원합니다. 콜센터 운영의 효율성과 서비스 품질을 동시에 추구합니다.', ARRAY['콜센터운영', '전화상담', '상담사교육', '통화품질', '대기시간단축', '상담프로세스'], '콜센터 운영 전반, 전화 상담 서비스, 상담사 관리 등 콜센터에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-3', '상담품질관리팀', '모든 상담 채널의 서비스 품질을 전문적으로 관리하고 개선하는 팀입니다. 상담 품질 기준 수립, 품질 모니터링, 상담사 평가, 개선 방안 도출 등을 담당하며, 일관되고 우수한 상담 서비스 품질을 보장합니다. 고객 만족도 향상을 위한 품질 관리 체계를 운영합니다.', ARRAY['상담품질관리', '품질기준', '품질모니터링', '상담사평가', '품질개선', '서비스표준화'], '상담 품질 관리, 서비스 기준, 품질 개선 등 상담 품질에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-4', '불만분석파트', '고객 불만과 컴플레인을 체계적으로 분석하고 개선 방안을 도출하는 조직입니다. 불만 유형 분류, 원인 분석, 개선 과제 도출, 재발 방지 대책 수립 등을 담당하며, 고객 불만을 서비스 개선의 기회로 전환시킵니다. 고객 목소리를 바탕으로 한 지속적인 서비스 혁신을 추진합니다.', ARRAY['불만분석', '컴플레인처리', '원인분석', '개선과제', '재발방지', '서비스개선'], '고객 불만 분석, 컴플레인 처리, 개선 방안 등 불만 분석에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-5', '응대품질셀', '상담사의 고객 응대 품질을 전문적으로 관리하고 개선하는 조직입니다. 응대 매뉴얼 작성, 상담 스크립트 개발, 응대 태도 개선, 고객 응대 스킬 향상 등을 담당하며, 모든 상담사가 일관되고 친절한 서비스를 제공할 수 있도록 지원합니다. 고객과의 모든 접점에서 우수한 서비스 경험을 보장합니다.', ARRAY['응대품질', '응대매뉴얼', '상담스크립트', '응대태도', '고객응대스킬', '서비스친절도'], '상담원 태도가 불친절함, 응대 품질 개선, 서비스 매뉴얼 등 고객 응대 품질 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-1-1', '챗봇상담연결파트', '챗봇과 인간 상담사 간의 연결 서비스를 전문적으로 관리하는 조직입니다. 챗봇이 해결하지 못한 문의를 적절한 상담사에게 연결하고, 고객 정보와 상담 이력을 원활하게 전달하여 끊김 없는 상담 서비스를 제공합니다. 디지털과 아날로그 상담의 완벽한 연계를 담당합니다.', ARRAY['챗봇상담연결', '상담사연결', '상담이력전달', '연결서비스', '하이브리드상담'], '챗봇 상담 연결, 상담사 연결 서비스, 상담 이력 전달 등 상담 연결에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('10-1-1-1', '연결오류분석셀', '챗봇에서 상담사로의 연결 과정에서 발생하는 오류를 전문적으로 분석하고 해결하는 최말단 기술 조직입니다. 연결 실패, 대기시간 초과, 상담 이력 누락, 시스템 오류 등을 즉시 진단하고 해결하여 고객이 원활하게 상담사와 연결될 수 있도록 보장합니다. 상담 연결의 기술적 안정성을 책임집니다.', ARRAY['연결오류분석', '연결실패', '대기시간초과', '상담이력누락', '시스템오류해결'], '상담원 연결이 안됨, 챗봇에서 연결이 끊어짐, 상담 대기시간 초과 등 상담 연결 관련 기술적 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('11', '리스크관리본부', '은행 운영과 고객 자산에 영향을 미칠 수 있는 모든 리스크를 체계적으로 관리하고 대응하는 조직입니다. 신용 리스크, 시장 리스크, 운영 리스크, 금융사기, 보이스피싱 등 다양한 위험 요소를 사전에 예방하고, 사고 발생 시 신속한 대응과 피해 최소화를 추진합니다. 안전하고 신뢰할 수 있는 금융 환경을 조성하여 고객과 은행을 보호합니다.', ARRAY['리스크관리', '위험관리', '금융사기', '보이스피싱', '피해보상', '사고대응', '리스크예방'], '리스크 관리 정책, 금융사고 대응 전략, 보상 정책 등 리스크 관리와 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 리스크 관리 전략이나 전반적인 위험 관리 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('11-1', '금융사고대응부', '보이스피싱, 계좌 도용, 금융사기 등 금융사고 발생 시 초기 대응과 전반적인 사고 관리를 담당하는 조직입니다. 사고 신고 접수, 피해 조사, 수사기관 협조, 재발 방지 대책 수립 등을 통해 금융사고로부터 고객을 보호하고 피해를 최소화합니다. 금융사고 대응의 컨트롤 타워 역할을 수행합니다.', ARRAY['금융사고대응', '보이스피싱대응', '계좌도용', '금융사기', '피해조사', '수사협조', '재발방지'], '금융사고 대응 전반, 사고 신고, 피해 조사 등 금융사고 대응에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('11-2', '피해보상심사팀', '금융사고로 인한 고객 피해의 보상 여부를 전문적으로 심사하는 팀입니다. 피해 사실 확인, 책임 소재 판단, 보상 범위 결정, 보상 금액 산정 등을 담당하며, 공정하고 객관적인 기준에 따라 피해 보상을 심사합니다. 고객 권익 보호와 은행 리스크 관리의 균형을 유지합니다.', ARRAY['피해보상심사', '보상여부심사', '책임소재판단', '보상범위결정', '보상금액산정', '공정심사'], '피해 보상 심사, 보상 기준, 심사 과정 등 피해 보상 심사에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('11-3', '보상처리파트', '심사가 완료된 피해 보상의 실제 지급 처리를 담당하는 조직입니다. 보상금 지급 절차 관리, 서류 처리, 지급 승인, 고객 안내 등을 통해 승인된 보상을 신속하고 정확하게 처리합니다. 고객이 피해 보상을 원활하게 받을 수 있도록 하는 실무 처리를 담당합니다.', ARRAY['보상처리', '보상금지급', '지급절차', '서류처리', '지급승인', '고객안내'], '보상 처리 과정, 지급 절차, 처리 시간 등 보상 처리에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('11-4', '보상지연셀', '피해 보상 처리가 지연되는 사례를 전문적으로 관리하고 해결하는 조직입니다. 지연 원인 분석, 처리 우선순위 조정, 고객 커뮤니케이션, 신속 처리 방안 마련 등을 통해 보상 지연으로 인한 고객 불편을 최소화합니다. 보상 처리의 신속성과 효율성을 보장하는 핵심 역할을 담당합니다.', ARRAY['보상지연', '지연원인분석', '처리우선순위', '신속처리', '지연해결', '효율성개선'], '피싱 피해 보상 언제 해주나요, 보상 처리가 너무 늦어요, 보상 지연 사유 등 보상 지연 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('12', '마케팅본부', '은행의 모든 마케팅 활동과 고객 유치 및 유지 전략을 총괄하는 조직입니다. 브랜드 관리, 광고 기획, 이벤트 진행, 고객 혜택 제공 등을 통해 은행의 브랜드 가치를 제고하고 고객 기반을 확대합니다. 디지털 마케팅부터 전통적인 마케팅까지 다양한 채널을 활용하여 효과적인 마케팅 캠페인을 기획하고 실행합니다.', ARRAY['마케팅', '브랜드관리', '광고기획', '고객유치', '고객유지', '마케팅캠페인', '브랜드가치'], '마케팅 전략, 브랜드 관리, 광고 캠페인 등 마케팅과 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 마케팅 전략이나 전반적인 브랜드 관리 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('12-1', '디지털마케팅부', '디지털 채널을 활용한 마케팅 활동을 전담하는 조직입니다. 온라인 광고, 소셜미디어 마케팅, 이메일 마케팅, 개인화 마케팅 등을 기획하고 실행하며, 데이터 분석을 통한 타겟 마케팅과 성과 측정을 담당합니다. 디지털 트렌드에 맞는 혁신적인 마케팅 전략을 수립하고 실행합니다.', ARRAY['디지털마케팅', '온라인광고', '소셜미디어마케팅', '개인화마케팅', '타겟마케팅', '데이터분석'], '디지털 마케팅 전반, 온라인 광고, 개인화 서비스 등 디지털 마케팅에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('12-2', '이벤트운영팀', '고객 대상 이벤트와 프로모션을 기획하고 운영하는 팀입니다. 계절별 이벤트, 신상품 출시 이벤트, 고객 감사 이벤트 등을 기획하고 실행하며, 이벤트 참여 고객 관리와 혜택 제공을 담당합니다. 고객 참여도와 만족도를 높이는 창의적이고 매력적인 이벤트를 지속적으로 개발합니다.', ARRAY['이벤트운영', '프로모션기획', '계절이벤트', '신상품이벤트', '고객참여', '이벤트관리'], '이벤트 운영, 프로모션 관리, 이벤트 참여 등 이벤트에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('12-3', '쿠폰지급파트', '마케팅 이벤트와 프로모션을 통해 제공되는 쿠폰과 혜택의 지급을 전문적으로 관리하는 조직입니다. 쿠폰 발행, 지급 조건 확인, 혜택 제공, 사용 내역 관리 등을 담당하며, 고객이 정당하게 획득한 혜택을 정확하고 신속하게 받을 수 있도록 지원합니다. 마케팅 효과를 극대화하는 혜택 관리 업무를 수행합니다.', ARRAY['쿠폰지급', '혜택제공', '쿠폰발행', '지급조건확인', '사용내역관리', '마케팅혜택'], '쿠폰 지급, 혜택 제공, 지급 조건 등 쿠폰 지급에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('12-4', '지급오류셀', '이벤트 쿠폰과 포인트, 혜택 지급 과정에서 발생하는 오류를 전문적으로 해결하는 조직입니다. 지급 누락, 중복 지급, 조건 미달 지급 등의 오류를 신속히 감지하고 수정하여 고객이 정확한 혜택을 받을 수 있도록 보장합니다. 마케팅 혜택 지급의 정확성과 신뢰성을 유지하는 핵심 역할을 담당합니다.', ARRAY['지급오류', '쿠폰누락', '혜택지급오류', '중복지급', '조건미달지급', '오류수정'], '이벤트 쿠폰이 안 들어옴, 포인트가 지급되지 않음, 혜택이 누락됨 등 마케팅 혜택 지급 관련 오류를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13', '준법감시본부', '은행의 모든 업무가 관련 법규와 규정에 적합하게 수행되도록 감시하고 관리하는 조직입니다. 금융 관련 법규 준수, 내부 통제 시스템 운영, 윤리 경영 추진, 컴플라이언스 위험 관리 등을 담당하며, 건전하고 투명한 은행 경영을 보장합니다. 법적 리스크를 사전에 예방하고 규제 당국과의 원활한 소통을 유지합니다.', ARRAY['준법감시', '컴플라이언스', '법규준수', '내부통제', '윤리경영', '규제대응', '법적리스크관리'], '준법 감시 정책, 법규 준수, 윤리 경영 등 컴플라이언스와 관련된 모든 이슈들을 포괄적으로 다룹니다. 특정 세부 업무가 아닌 준법 정책이나 전반적인 컴플라이언스 관련 문의를 직접 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-1', '전자금융준법팀', '전자금융거래법 등 디지털 금융 서비스 관련 법규의 준수를 전담하는 팀입니다. 전자금융 약관 관리, 동의 절차 점검, 개인정보 보호, 전자금융 안전성 확보 등을 담당하며, 디지털 금융 서비스가 관련 법규에 적합하게 운영되도록 감시합니다. 전자금융 분야의 전문적인 준법 업무를 수행합니다.', ARRAY['전자금융준법', '전자금융거래법', '디지털금융규제', '전자금융약관', '개인정보보호'], '전자금융 준법, 약관 관리, 디지털 서비스 규제 등 전자금융 준법에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-2', '내부통제부', '은행 내부의 통제 시스템과 프로세스를 설계하고 운영하는 조직입니다. 내부 감사, 리스크 통제, 업무 프로세스 점검, 내부 규정 관리 등을 담당하며, 은행 운영의 투명성과 건전성을 보장합니다. 내부 통제 시스템의 효과성을 지속적으로 개선하고 강화합니다.', ARRAY['내부통제', '내부감사', '리스크통제', '프로세스점검', '내부규정관리', '운영투명성'], '내부 통제 시스템, 감사 프로세스, 내부 규정 등 내부 통제에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-3', '윤리신고관리팀', '은행 내부의 윤리 위반 신고와 관련된 업무를 전문적으로 관리하는 팀입니다. 윤리 신고 접수, 신고 사건 조사, 조치 방안 수립, 재발 방지 대책 마련 등을 담당하며, 공정하고 투명한 윤리 경영 문화를 조성합니다. 윤리 위반 행위를 사전에 예방하고 발생 시 적절한 조치를 취합니다.', ARRAY['윤리신고관리', '윤리위반신고', '신고사건조사', '윤리경영', '투명경영', '재발방지'], '윤리 신고 관리, 윤리 경영, 신고 프로세스 등 윤리 신고에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-4', '신고접수파트', '각종 위반 행위와 불법 행위에 대한 신고를 접수하고 초기 처리하는 조직입니다. 신고 채널 관리, 신고자 보호, 신고 내용 분류, 담당 부서 배정 등을 담당하며, 신고자가 안전하고 편리하게 신고할 수 있는 환경을 조성합니다. 신고 처리의 시작점 역할을 수행합니다.', ARRAY['신고접수', '신고채널관리', '신고자보호', '신고내용분류', '초기처리'], '신고 접수 프로세스, 신고 채널, 신고자 보호 등 신고 접수에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-5', '비위분석셀', '접수된 신고 사건과 비위 행위를 전문적으로 분석하고 조사하는 조직입니다. 사실 관계 확인, 증거 수집, 위반 정도 분석, 조치 방안 제안 등을 담당하며, 객관적이고 공정한 조사를 통해 진실을 규명합니다. 조직 내 비위 행위 근절과 건전한 조직 문화 조성에 기여합니다.', ARRAY['비위분석', '사실관계확인', '증거수집', '위반정도분석', '조사업무', '진실규명'], '개인정보 유출이 걱정됨, 직원 비위 신고는 어디서 하나요 등 비위 분석과 조사 관련 문제를 전문적으로 해결합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-1-1', '약관관리파트', '전자금융 서비스의 약관과 이용 조건을 전문적으로 관리하는 조직입니다. 약관 작성, 개정, 고객 동의 절차 설계, 약관 공시 등을 담당하며, 고객이 이해하기 쉽고 법적 요건을 충족하는 약관을 제공합니다. 전자금융 서비스의 법적 기반을 마련하는 핵심 업무를 수행합니다.', ARRAY['약관관리', '전자금융약관', '이용조건', '약관개정', '고객동의절차', '약관공시'], '약관 관리, 동의 절차, 이용 조건 등 약관 관리에 관련된 이슈들을 처리합니다.');

INSERT INTO organizations (org_id, org_name, role_responsibility, keywords, review_types)
VALUES ('13-1-1-1', '동의절차분석셀', '고객의 약관 동의 절차를 전문적으로 분석하고 개선하는 최말단 조직입니다. 동의 절차의 적법성, 명확성, 편의성을 검토하고, 고객이 충분히 이해하고 동의할 수 있는 절차를 설계합니다. 약관 동의의 법적 유효성을 보장하고 고객 편의성을 동시에 추구합니다.', ARRAY['동의절차분석', '절차적법성', '동의명확성', '절차편의성', '법적유효성'], '약관 동의가 너무 복잡함, 법적 안내가 부족함, 동의 절차 개선 등 동의 절차 관련 문제를 전문적으로 해결합니다.');
